            {"shader": "stable_fluids_jacobi", "writes": ["p2"]},
            {"shader": "stable_fluids_jacobi", "writes": ["p2"]},
            {"shader": "stable_fluids_jacobi", "writes": ["p2"]},
            {"shader": "stable_fluids_jacobi", "writes": ["p2"]},
            {"shader": "stable_fluids_jacobi", "writes": ["p2"]},
